package com.cognizant.springtesting;import static org.junit.jupiter.api.Assertions.assertEquals;import org.junit.jupiter.params.ParameterizedTest;import org.junit.jupiter.params.provider.CsvSource;public class CalculatorServiceParameterizedTest {@ParameterizedTest @CsvSource({"2, 3, 5","5, 5, 10","-1, 1, 0","0, 0, 0"}) void testAdd(int a,int b,int expected){CalculatorService calculatorService=new CalculatorService();assertEquals(expected,calculatorService.add(a,b));}}
